INSERT INTO public.photos VALUES (24238, 'Pl. de Basilio Para├¡so 1953', 'Imagen capturada en el entorno de la plaza de Basilio Para├¡so durante el paso de la local comparsa de Gigantes y Cabezudos que parece estar bajando desde el paseo del General Mola. En primer t├®rmino, el cabezudo Forano latiguea pardales. Al fondo encabezan el paso de los Gigantes, posiblemente, las figuras del Rey, la Reina, el Duque y la Duquesa de Villahermosa. La rotunda presencia de la gran fachada principal del colegio del Salvador de los PP. Jesuitas ofrece un marco incomparable para cerrar el campo visual. Desde el', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.64718600, -0.88574000, '0101000020E61000000E4A9869FB57ECBFEB36A8FDD6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39772909184.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39772909184.webp', 'https://www.flickr.com/photos/zaragozaantigua/39772909184/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24258, 'Huerva cubierto 1927', 'Imagen del cubrimiento del r├¡o Huerva en su urbano tramo primero (Curva de "La Veneciana"-Puente de Santa Engracia). A la derecha, el edificio del Hospital Cl├¡nico junto a la Facultad de Medicina y Ciencias. Las obras, en este tramo, est├ín pr├ícticamente finalizadas, y es perceptible el destacado desnivel entre un lado y otro del nuevo vial. Fuente visual: "Arag├│n : revista gr├ífica de cultura aragonesa" (A├▒o III, N┬║ 16, enero 1927).', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64691500, -0.88584000, '0101000020E6100000F0A2AF20CD58ECBF5B25581CCED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15661755442.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15661755442.webp', 'https://www.flickr.com/photos/zaragozaantigua/15661755442/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24259, 'R├¡o Huerva 1900', 'Imagen desde el Puente de Santa Engracia del cauce del r├¡o Huerva. A la derecha, la Facultad de Medicina y Ciencias. A la izquierda, el Vel├│dromo de los Campos El├¡seos. Fuente visual: www.bildarchivaustria.at/', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64691500, -0.88584000, '0101000020E6100000F0A2AF20CD58ECBF5B25581CCED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16041516225.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16041516225.webp', 'https://www.flickr.com/photos/zaragozaantigua/16041516225/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24883, 'Pl. de Basilio Para├¡so 1940', 'AHPZ-Archivo Coyne, Manuel Coyne, 1940. Plaza de Basilio Para├¡so, con la estatua de C├®sar Augusto. Al fondo, la Facultad de Medicina y Ciencias.', 1940, 1940, 1940, 'Anos 40', 'CENTRO', 41.64766200, -0.88563300, '0101000020E61000008D4468041B57ECBF546EA296E6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14883103041.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14883103041.webp', 'https://www.flickr.com/photos/zaragozaantigua/14883103041/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25638, 'La Romareda c.1972', 'Imagen capturada desde la altura de la Residencia Sanitaria "Jos├® Antonio" y centrada en el original aspecto del estadio municipal de La Romareda un domingo de liga, con el entorno invadido por abundante parque automovil├¡stico. Pocos a├▒os despu├®s conocer├¡a su primera gran ampliaci├│n. A la derecha, vista del Pabell├│n Franc├®s de la inmediata Feria de Muestras. Al fondo, desarrollo urban├¡stico del Pol├¡gono de la Gran V├¡a, tras el que todav├¡a verdean campos de herb├íceas. Entre los dos bloques en construcci├│n, en el centro de la imagen, se ubicar├¡a algo m├ís tarde el Pabell├│n Municipal de Deportes.', 1972, 1972, 1972, 'Anos 70', 'UNIVERSIDAD', 41.63629300, -0.90167200, '0101000020E61000005401F73C7FDAECBF3DD68C0C72D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49502395181.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49502395181.webp', 'https://www.flickr.com/photos/zaragozaantigua/49502395181/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24894, 'Plaza de Para├¡so 1966', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 23/11/1966. Una aut├®ntica "performance" a la zaragozana, con elementos de arquitectura, escultura, publicidad, y urbanismo. La imagen est├í tomada en el arranque del Paseo de Marina Moreno (sigue hacia la izquierda). Al fondo, la esquina del colegio de los jesuitas, a├║n ah├¡. Delante, un cartel├│n publicitario del Ayuntamiento de Zaragoza, patrocinado (pagado) por la empresa "Pegaso", de fomento de la "Cortes├¡a" en el tr├ífico mediante una campa├▒a de sensibilizaci├│n. Esta campa├▒a incluy├│ un premio de Prensa y Radio para los periodistas m├ís sensibilizadores. La edici├│n de ese a├▒o fue ganada por Alberto Albericio Conch├ín (Radio Juventud de Zaragoza). Y de guinda, la escultura "La siesta" de Enrique Galcer├í, donada al Ayuntamiento tras haber recibido de la Diputaci├│n de Zaragoza la medalla de plata de la Bienal de Pintura y Escultura de Zaragoza (1963). Est├í echadica, sin saberlo, claro, justo en un espacio muy constitucional, pero varias d├®cadas despu├®s.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.64719700, -0.88503200, '0101000020E61000002A3BFDA02E52ECBFDF88EE59D7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15203260646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15203260646.webp', 'https://www.flickr.com/photos/zaragozaantigua/15203260646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24914, 'Facultad de Medicina 1933', 'Facultad de Medicina y Ciencia. Hacia la derecha, e inmediata, la plaza de Arag├│n. Detr├ís, el paseo de Pamplona. Fuente visual: Foto Conrado Barl├®s, donada por Daniel Barl├®s y digitalizada por Jos├® Luis Cintora para www.rafaelcastillejo.com', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.64758900, -0.88581600, '0101000020E6100000CFC0C8CB9A58ECBFEB1F4432E4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22875466699.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22875466699.webp', 'https://www.flickr.com/photos/zaragozaantigua/22875466699/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24964, 'Vel├│dromo Campos El├¡seos 1896', '1896. Inaugurado en 1895, reconvertido parcialmente en garaje de motos y bicicletas en 1908 y derribado en 1920. Situado en la actual esquina del paseo de Sagasta con la plaza Para├¡so, donde el cine El├¡seos conserva el recuerdo de su nombre.', 1896, 1896, 1896, 'Siglo XIX', 'CENTRO', 41.64666500, -0.88573700, '0101000020E6100000CA6DFB1EF557ECBFE23B31EBC5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14918261752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14918261752.webp', 'https://www.flickr.com/photos/zaragozaantigua/14918261752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25015, 'P┬║ del General Mola 1937', 'Vista a├®rea del primer tramo del paseo del General Mola, redenominaci├│n de la avenida de la Rep├║blica tras el fallecimiento de este general golpista. Incluye el 25% de la superficie del proyectado (lo ejecutado es otra historia) ensanche de Miraflores. Fuente visual: www.facebook.com/photo.php?fbid=10204363057770144&set...', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.64622300, -0.88547900, '0101000020E6100000DF6E490ED855ECBF25766D6FB7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14847204898.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14847204898.webp', 'https://www.flickr.com/photos/zaragozaantigua/14847204898/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25029, 'P.┬║ de Sagasta c.1912', 'Imagen capturada desde el interior de los jardines del colegio del Salvador de los PP. Jesuitas, en su estrat├®gica ubicaci├│n entre el r├¡o Huerva y el arranque del ensanche del paseo de Sagasta. Con edici├│n de ├üngel Toldr├í Viazo, en Barcelona, esta fotograf├¡a form├│ parte de una serie de postales alusiva a este colegio, denominada precisamente "Jardines del Colegio". En primer plano, y desde cierta altura, los referidos jardines que ornamentaban el acceso desde el paseo de Sagasta, que queda tras el muro perimetral en ladrillo. Justo enfrente, la notable puerta monumental que permit├¡a el ingreso al Vel├│dromo de los Campos El├¡seos. De izquierda a derecha, la fronda arb├│rea se├▒ala el cauce al aire del r├¡o Huerva, salvado por el puente de Santa Engracia. Al fondo destaca el destacado complejo de la Facultad de Medicina y Ciencias, y las Cl├¡nicas Universitarias. Fuente visual: www.delcampe.es/', 1912, 1912, 1912, 'Anos 10', 'CENTRO', 41.64667800, -0.88532000, '0101000020E6100000BFD4CF9B8A54ECBF77853E58C6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27405182960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27405182960.webp', 'https://www.flickr.com/photos/zaragozaantigua/27405182960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25033, 'P.┬║ de Sagasta c.1902', 'Imagen capturada en altura, posiblemente desde el edificio de la Facultad de Medicina y Ciencias, de la gran mole en "U" del colegio del Salvador. Su fachada principal, solanera, recayente a los jardines de acceso desde el paseo de Sagasta. En primer plano, el puente de Santa Engracia, y el acceso peatonal a la puerta de Santa Engracia e ingreso a la plaza de Arag├│n, a la izquierda. Al fondo, la arboleda fluvial del Huerva serpentea junto a la antigua huerta de Santa Engracia, con vista de algunas de las instalaciones harineras ubicadas en torno a su cauce, hasta el puente de San Jos├®. A la derecha, despejada vista de los campos de las Adulas, entre el paseo de las Damas, y el camino de las Torres. Fuente: Fototipia Lucas Escol├í, en www.ebay.es/', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.64667800, -0.88532000, '0101000020E6100000BFD4CF9B8A54ECBF77853E58C6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31449357142.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31449357142.webp', 'https://www.flickr.com/photos/zaragozaantigua/31449357142/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25035, 'P.┬║ del General Mola 1978', 'Paso de la comparsa de Gigantes y Cabezudos de Zaragoza por el paseo de Sagasta, en octubre de 1978. Al fondo, el Cinema El├¡seos (1944-2014) proyecta el estreno en Espa├▒a del documental "Morir en Madrid" (Fr├®d├®ric Rossif, 1963), sobre la Guerra Civil. El Estado hab├¡a dado todas las facilidades al filme, creyendo que se trataba de un paneg├¡rico franquista. Al verse traicionados, encargaron dos pel├¡culas de r├®plica, a Eduardo Manzanos y Mariano Ozores. Fuente visual: Heraldo de Arag├│n.', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.64647300, -0.88565600, '0101000020E6100000983270404B57ECBF9E5F94A0BFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31943514371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31943514371.webp', 'https://www.flickr.com/photos/zaragozaantigua/31943514371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25037, 'P.┬║ del General Mola 1977', 'Imagen con el solar del desaparecido colegio del Salvador en el arranque del paseo del General Mola, en este caso como provisional y alegre recinto ferial para un circo. Al fondo, el edificio "El├¡seos" con su publicitaria peineta, chaflanero con el paseo de Calvo Sotelo. En el centro, el edificio de la antigua facultad de Medicina y Ciencias. A la derecha, edificios del paseo de Pamplona. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.64660900, -0.88474400, '0101000020E610000094A12AA6D24FECBF4E266E15C4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32288614533.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32288614533.webp', 'https://www.flickr.com/photos/zaragozaantigua/32288614533/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26078, 'Vista desde Santa Engracia c.1902', 'Vista capturada desde la altura de las torres de la iglesia de Santa Engracia, con orientaci├│n hacia el norte.', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.64910600, -0.88288600, '0101000020E6100000871403249A40ECBF96D1C8E715D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53816308332.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53816308332.webp', 'https://www.flickr.com/photos/zaragozaantigua/53816308332/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25042, 'Puente de Santa Engracia c.1895', 'In├®dita imagen que muestra desde la margen izquierda del r├¡o Huerva, y de forma parcial, el puente de Santa Engracia construido en piedra sillar en 1855 y alineado con el paseo de la Lealtad. Al fondo y a la izquierda destaca la gran mole edilicia del colegio del Salvador que se├▒ala el arranque del densamente arbolado paseo de Sagasta. A├▒os despu├®s, durante las obras de cubrimiento del Huerva, este paso hacia el paseo de las Damas, y el de Sagasta, fue considerablemente ensanchado y reorientado m├ís hacia la plaza de Arag├│n, "comi├®ndose" la inmediata construcci├│n que aqu├¡ aparece tras el puente, y llegando hasta el per├¡metro de los jardines de entrada al colegio, de forma que el puente de Santa Engracia qued├│ ya oculto a la vista para siempre. En la fotograf├¡a, la circulaci├│n por el puente parece ser bien escasa, de forma que el se├▒or tancredo apoyado sobre la barandilla no puede sino fijarse en el pausado tr├ínsito de un ocasional veloc├¡pedo, tras el que un ni├▒o vendedor de peri├│dicos aguarda paciente el paso de clientes.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64686100, -0.88561100, '0101000020E6100000994A3FE1EC56ECBF68075C57CCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48030546323.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48030546323.webp', 'https://www.flickr.com/photos/zaragozaantigua/48030546323/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25043, 'Paseo de Sagasta c.1895', 'Infrecuente imagen capturada en la umbr├¡a del primer tramo del paseo de Sagasta como bulevar frondosamente arbolado, a la altura de la glorieta que, hacia la izquierda, marcaba el arranque del paseo de las Damas; a la derecha, albinos muros del ingreso al nuevo vel├│dromo de los Campos El├¡seos, que sustituy├│ al anterior y hom├│nimo Circo, tambi├®n utilizado como ocasional plaza de toros. Sobre el terroso pavimento del bulevar, y a los laterales, tendido tranviario de la l├¡nea de Torrero, que en tiempos de vigencia de la tracci├│n de sangre apenas supon├¡a las v├¡as sobre las que ascend├¡an los coches tirados por caballer├¡as hasta la playa de Torrero, para descender luego hasta la plaza de la Constituci├│n.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64614700, -0.88562200, '0101000020E610000093C7D3F20357ECBF4AB4E4F1B4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48051884826.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48051884826.webp', 'https://www.flickr.com/photos/zaragozaantigua/48051884826/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25045, 'P.┬║ de Sagasta c.1901', 'Imagen capturada en el principio del terroso paseo de Sagasta y orientada hacia el puente de Santa Engracia sobre el r├¡o Huerva. A la izquierda y fuera de plano, el vel├│dromo de los Campos El├¡seos, y al otro lado del r├¡o destaca el edificio de las facultades de Medicina y Ciencias. Al fondo, la Glorieta de Pignatelli. A la derecha y fuera de plano, jardines del ingreso al colegio del Salvador. En primer t├®rmino, unas caballer├¡as tiran de un cargado carro hacia Torrero.', 1901, 1901, 1901, 'Anos 1900', 'CENTRO', 41.64639900, -0.88540700, '0101000020E61000007AC8940F4155ECBF6495D233BDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49885576583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49885576583.webp', 'https://www.flickr.com/photos/zaragozaantigua/49885576583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25048, 'P.┬║ de Sagasta 1893', 'Imagen capturada pasado el puente de Santa Engracia, con una interesante perspectiva desde el punto de vista de los peatones, del ascendente y terroso camino de Torrero hacia el fondo. A la derecha, murete que delimitaba el Circo de los Campos El├¡seos, ante el que desciende un veh├¡culo traccionado por caballer├¡a, como hac├¡an los tranv├¡as de la l├¡nea de Torrero que por all├¡ circulaban. Al fondo, isleta triangular que hac├¡a las veces de despartidero entre el camino de Torrero y el paseo de las Damas, y tras cuya foresta se perfila levemente el colegio del Sagrado Coraz├│n.', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64666800, -0.88554700, '0101000020E6100000E94482A96656ECBF53AF5B04C6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50159816452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50159816452.webp', 'https://www.flickr.com/photos/zaragozaantigua/50159816452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25056, 'Estatua C├®sar Augusto 1940', 'En junio de 1940 tuvo lugar en Zaragoza una "Semana Aug├║stea", con presencia de jerarqu├¡as varias de los reg├¡menes fascistas de Italia y Espa├▒a. Hubo misa en la capilla del Pilar; visita a las ruinas de Velilla, Azaila, y Numancia; conferencias en el Paraninfo de la Facultad de Medicina. Clausur├│ el Rector de la Universidad de Zaragoza, que termin├│ con vivas a Italia y a Espa├▒a, al Duce y a Franco. Dentro de los actos organizados, el 2 de junio fue inaugurada la estatua de C├®sar Augusto regalada por el Duce (el fascista Benito Mussolini) a la ciudad de Zaragoza. A tal fin acudieron a Zaragoza el Ministro de Educaci├│n Nacional, el aciago Jos├® Ib├í├▒ez Mart├¡n, y el Presidente de la Junta Pol├¡tica, Ram├│n Serrano S├║├▒ez (meses antes de ser designado como Ministro de Asuntos Exteriores). La estatua, en bronce, copia el original de Prima Porta. Su ubicaci├│n provisional fue la Plaza de Basilio Para├¡so, aunque estuvo all├¡ hasta octubre de 1950, en que fue reinstalado en las Murallas Romanas, en la Plaza de C├®sar Augusto. En la imagen, a la derecha, el alcalde de Zaragoza, Juan Jos├® Rivas Bosch, escuchando a Serrano S├║├▒er en la fervorosa y nacionalista inauguraci├│n de la estatua, hablando de lo que un├¡a a italianos y a espa├▒oles como herederos directos de Augusto. Romanistas de todo el mundo siguen tratando de descifrar lo que eso significa. Fuente visual: Instant├íneas zaragozanas. Caja de Ahorros y Monte de Piedad de Zaragoza, Arag├│n y Rioja, 1982.', 1940, 1940, 1940, 'Anos 40', 'CENTRO', 41.64750200, -0.88568100, '0101000020E6100000D10836AE7F57ECBF1C0C7558E1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14766290069.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14766290069.webp', 'https://www.flickr.com/photos/zaragozaantigua/14766290069/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25195, 'Puente de Santa Engracia 1840', 'Plano con plantas y alzado del proyecto para el puente de Santa Engracia sobre el r├¡o Huerva. Jos├® de Yarza y Joaqu├¡n Gironza, Zaragoza, 4 de enero de 1840. Este puente, proyectado para sustituir el puente de madera arrastrado por las aguas del Huerva en 1838, fue finalmente construido en 1855 en piedra sillar. Desapareci├│ con el cubrimiento del r├¡o en los a├▒os veinte del siglo XX.', 1840, 1840, 1840, 'Siglo XIX', 'CENTRO', 41.64713800, -0.88567300, '0101000020E61000001B683EE76E57ECBFDAFF006BD5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23898032160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23898032160.webp', 'https://www.flickr.com/photos/zaragozaantigua/23898032160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25200, 'P.┬║ de la Independencia 1955', 'AHPZ-Archivo Coyne, Manuel Coyne. Paseo de la Independencia y Plaza de Arag├│n.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64807900, -0.88496800, '0101000020E61000007A354069A851ECBFB91CAF40F4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14694377839.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14694377839.webp', 'https://www.flickr.com/photos/zaragozaantigua/14694377839/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25205, 'Plaza de Pignatelli 1889', '1889. El Archivo Roger Viollet contiene una instant├ínea del "Estudio Fotogr├ífico J. L├®vy et Cie" titulada "Place de Pignatelli" (Plaza de Pignatelli), otro destacado ejemplo de lo inapropiado de decir que algo en Zaragoza es as├¡, o est├í, "desde siempre". Para el caso que nos ocupa, desde el a├▒o de 1859 estuvo en el centro de esa glorieta (y en el centro de la imagen), luego plaza, d├índole su nombre, la bronc├¡nea estatua del pr├│cer don Ram├│n Pignatelli y Moncayo, obra de Antonio Palao. All├¡ estuvo hasta que en 1904 fue trasladada 1326 metros m├ís al sur, en los terrenos de la aterrazada y antigua Torre de Pablo Buil, que devino en el primer parque de la ciudad, y adquiri├│ ilustrada denominaci├│n: Parque Pignatelli. El hueco dejado por la oronda estatua fue pronto rellenado con una sedente imagen del justicia ajusticiado, y a la plaza se la empez├│ a denominar "de Arag├│n". Mientras estuvo en esta tan c├®ntrica localizaci├│n, la estatua de Don Ram├│n permanec├¡a rodeada de una verja y unos frondosos jardines, y era habitual lugar de encuentro de paseantes y peatones del entonces Paseo de Santa Engracia (hoy, Independencia). De esta imagen apenas encontramos supervivencias que no sean, al fondo, a la derecha de la estatua, el ondulante chapitel de la torre de la Seo, y el remate de una de las torres de Santa Engracia (junto a la gran farola de la derecha). A la izquierda, se alza nov├¡simo (de 1888) el edificio de viviendas de la Plaza Arag├│n 12. A continuaci├│n, el edificio de viviendas del Paseo Independencia 34-36, antes de ser reformado, que conten├¡a desde este mismo a├▒o 1889, en sus bajos, el caf├® "Ambos Mundos"... El paisanaje conforma un cuadro antropol├│gico de la realidad social de la Zaragoza de finales del XIX, y el entorno urbano ilustra otra ciudad, tambi├®n llamada Zaragoza, pero que no es la actual: los chalecitos vallados de la Plaza Arag├│n, el Teatro Pignatelli, el Convento de Jerusal├®n... Fuente: "Zaragoza en la mirada ajena. Instant├íneas del archivo Roger-Violle', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.64769500, -0.88560600, '0101000020E61000002786E464E256ECBF306475ABE7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14878858183.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14878858183.webp', 'https://www.flickr.com/photos/zaragozaantigua/14878858183/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25207, 'Panor├ímica 1954', 'Unas impresionantes im├ígenes nos dan juego para mostrar una panor├ímica ins├│lita. Fueron capturadas desde lo alto del estrat├®gico n┬║ 2-4 del Paseo de Mola (antes del 18 de julio de 1936, Avenida de la Rep├║blica), obra ideada por Teodoro R├¡os Balaguer apenas una d├®cada antes (1945). Desde esta privilegiada altura, y gracias a la excepcional calidad de imagen, la visual alcanza, al fondo a la izquierda, hasta los escarpes de Juslibol y el Castellar. Al fondo, a la derecha, llegamos hasta la Sierra de Alcubierre. De izquierda a derecha podemos visualizar: las torrecillas del Hogar Pignatelli y alguno de sus talleres de trabajo; las traseras del Convento-Noviciado de la Congregaci├│n de las Hermanas de la Caridad de Santa Ana, en la calle Madre Rafols; algunas instalaciones y la barroca c├║pula del Hospital Provincial de N┬¬ S┬¬ de Gracia; las huertas donde a├▒os despu├®s se levantar├í el nuevo Monasterio de la Encarnaci├│n de las Madres Carmelitas; la Puerta del Carmen; el Paseo de Pamplona a├║n con su andador central peatonal; el edificio chafl├ín con la calle Doctor Cerrada, antes de la reforma que le dio su actual y acristalado remate; al fondo, se eleva la chimenea de la Azucarera Agr├¡cola "El Pilar", en la calle Santa Luc├¡a; la torre de la iglesia de San Pablo; la c├║pula de Santiago el Mayor, antes de su reforma de finales de d├®cada. Descanso. La plaza de Arag├│n y el Paseo de la Independencia, "provincianos" (en lenguaje desarrollista) con su paseo central y zonas verdes, antes de su "reforma" automovil├¡stica de comienzos de los 60; la plaza de Arag├│n a├║n poblada con sus hotelitos de finales del XIX-primeros a├▒os del XX; una composici├│n motor-remolque de la serie 100 de la l├¡nea 5 "Venecia-Delicias" enfila hacia Mola; al fondo, en el Coso Alto, los torreones pareados de la antigua Casa de los Luna, luego Audiencia; el moderno edificio de seguros "La Adri├ítica", la c├║pula de la iglesia de la Manter├¡a en la plaza de San Roque, y la vigorosa y vecina c├║pula del Banco de Arag├│n;', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64750200, -0.88568100, '0101000020E6100000D10836AE7F57ECBF1C0C7558E1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16100773069.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16100773069.webp', 'https://www.flickr.com/photos/zaragozaantigua/16100773069/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25218, 'Plaza de Arag├│n 1892', 'Imagen parcial de la antigua glorieta de Pignatelli, capturada a ras de suelo en el despejado espacio que se extend├¡a desde la arboleda en torno al monumento a Pignatelli, y hasta la puerta de Santa Engracia, en primer plano. Al fondo, a la derecha, la nov├¡sima Facultad de Medicina y Ciencias, pr├ícticamente acabada aunque no inaugurada. Al fondo, a la izquierda, el puente de Santa Engracia, y el cauce del Huerva al aire. Hemos volteado horizontalmente la original imagen para disfrutar mejor del juego de luces y sombras. Fuente visual: Estudio Coyne, AHPZ.', 1892, 1892, 1892, 'Siglo XIX', 'CENTRO', 41.64785400, -0.88552600, '0101000020E61000000C3F389F3A56ECBF994A3FE1ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31271815980.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31271815980.webp', 'https://www.flickr.com/photos/zaragozaantigua/31271815980/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25219, 'Plaza de Arag├│n 1892', 'Canicular imagen parcial de la antigua glorieta de Pignatelli, capturada a ras de suelo poco antes de su ingreso por la puerta de Santa Engracia, en primer plano. Al fondo, a la izquierda, la arboleda en torno al monumento a Pignatelli, de la que emergen t├¡midamente los remates del Teatro Pignatelli, y posiblemente la torre oriental de Santa Engracia. A la derecha, el nov├¡simo hotelito dise├▒ado por el veterano arquitecto zaragozano Mariano L├│pez Altaoja en el solar del extremo sureste de la plaza correspondiente al n├║mero 8, por encargo de Ram├│n Gironza. Sobre el firme, el tendido tranviario de subida de la l├¡nea de Torrero, tirado por caballer├¡as, que coexisti├│ con la puerta de Santa Engracia, hasta que fue derribada. Fuente visual: Estudio Coyne, AHPZ.', 1892, 1892, 1892, 'Siglo XIX', 'CENTRO', 41.64785400, -0.88552600, '0101000020E61000000C3F389F3A56ECBF994A3FE1ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31272872100.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31272872100.webp', 'https://www.flickr.com/photos/zaragozaantigua/31272872100/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25223, 'Glorieta de Pignatelli 1889', 'Imagen capturada sobre tr├¡pode, y desde algo de altura, un soleado d├¡a de finales de invierno en la glorieta de Pignatelli, a espaldas de la Puerta de Santa Engracia, y tambi├®n del Sol, como indican los paisanos y paisanas que desde la poblada glorieta miran hacia el objetivo fotogr├ífico protegi├®ndose los ojos de los rayos directos, en una abigarrada composici├│n de personajes. Hacia el fondo, y de derecha a izquierda, el destacado volumen del Teatro Pignatelli, el Monumento a Pignatelli antes de ser exiliado pol├¡ticamente hacia el sur, la calle de la Independencia y algunas de las primeras viviendas unifamiliares construidas sobre los solares parcelados donde tuvo lugar la Exposici├│n Aragonesa de 1868, como la pionera del n┬║ 13 de la glorieta, esquinera con la calle de Jos├® Luis Albareda. Esta antropol├│gica imagen se comercializ├│ en la Rep├║blica de Francia, y editada en formato m├ís peque├▒o, en el Imperio alem├ín.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.64795900, -0.88512800, '0101000020E6100000B1C398F4F752ECBF0E130D52F0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48169492932.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48169492932.webp', 'https://www.flickr.com/photos/zaragozaantigua/48169492932/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25224, 'Pl. de Arag├│n c.1950', 'Imagen capturada desde cierta altura en el reciente Edificio El├¡seos, y centrada en la plaza de Arag├│n y el paseo de la Independencia. Esta vista presenta varias singularidades, in├®ditas hasta ahora en el el Gran Archivo Zaragoza Antigua, como la vista de la isleta de la plaza de Basilio Para├¡so, ppoco despu├®s reformada, que a la izquierda y en primer t├®rmino muestra el pedestal vac├¡o sobre el que desde 1940 y hasta 1950 se alz├│ la estatua que representaba a Cayo Octavio Augusto, regalada por el gobierno del Reino de Italia presidido por Benito Mussolini para conmemorar la fundaci├│n de la Colonia Cesaraugusta por las legiones romanas III Maced├│nica, VI Victrix y X Gemina hacia el a├▒o 15 antes de nuestra Era. Esta estatua se convirti├│ en un bien semoviente desde entonces y durante bastantes d├®cadas, siendo ubicada en varias localizaciones de la ciudad. En la plaza de Arag├│n se destacan algunos de los hotelitos que en la d├®cada de los a├▒os cuarenta fueron reformados de forma intensa, como el del n┬║ 12, a la izquierda, reci├®n recrecido en altura con proyecto de Miguel ├üngel Navarro y Jos├® Luis Anguela. Por encima de ├®l, adem├ís, se aprecia al fondo el alzamiento del edificio de Seguros La Adri├ítica, y el de la sede central del Banco de Arag├│n, ambos nov├¡simos inmuebles que flanquean la nueva plaza de San Roque, reformada radicalmente tras el derribo del Arco de San Roque.', 1950, 1950, 1950, 'Anos 50', 'CENTRO', 41.64759800, -0.88539700, '0101000020E6100000963FDF162C55ECBF3E7AC37DE4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48364964326.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48364964326.webp', 'https://www.flickr.com/photos/zaragozaantigua/48364964326/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25231, 'Plaza de Arag├│n c.1955', 'Vista en altura de la plaza de Arag├│n.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64788800, -0.88535700, '0101000020E6100000081C0934D854ECBF45BC75FEEDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54382740255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54382740255.webp', 'https://www.flickr.com/photos/zaragozaantigua/54382740255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25233, 'Puente de Santa Engracia 1861', 'Imagen capturada desde la ribera izquierda del r├¡o Huerva, casi a nivel del cauce, y centrada en el nuevo puente de piedra sillar de Santa Engracia, construido en 1855 para dar acceso al camino y paseo de Torrero. A la izquierda y fuera de plano, sobre la trinchera del r├¡o, el Campo de Lezcano donde en unos a├▒os se construir├¡a la nueva Facultad de Medicina y Ciencias.A la derecha, la Torre de Montadas, donde a├▒os m├ís tarde se levantar├¡a en gran colegio del Salvador.', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.64701100, -0.88575800, '0101000020E6100000A87345292158ECBF7D93A641D1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14710709750.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14710709750.webp', 'https://www.flickr.com/photos/zaragozaantigua/14710709750/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25234, 'Pl. de Basilio Para├¡so 1954', '1954. Vista a├®rea del entorno de la plaza de Basilio Para├¡so. En el centro, el colegio de los Jesuitas. La ef├¡mera iglesia anexa est├í siendo construida en el paseo de las Damas, mientras que en Marina Moreno se levanta la residencia de estudiantes, que a├▒os m├ís tarde se convertir├¡an en residencias civiles.', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64677100, -0.88490100, '0101000020E61000008753E6E61B51ECBF28806264C9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14963318242.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14963318242.webp', 'https://www.flickr.com/photos/zaragozaantigua/14963318242/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25239, 'Plaza Para├¡so 2011', 'Foto: Maite Santonja. La fuente inaugurada en 1991 en el centro de la plaza de Basilio Para├¡so de Zaragoza fue desmantelada el 25 de julio de 2011 con motivo de las obras del nuevo tranv├¡a, momento que recoge la imagen. Ya hab├¡a habido ah├¡ una fuente luminosa circular entre 1961 y 1975. En la toma, al fondo el paseo de Pamplona. Fuente: Heraldo de Arag├│n.', 2011, 2011, 2011, 'Siglo XXI', 'CENTRO', 41.64714800, -0.88547300, '0101000020E610000056B60F79CB55ECBFFED5E3BED5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19393697748.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19393697748.webp', 'https://www.flickr.com/photos/zaragozaantigua/19393697748/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25240, 'Pl. de Para├¡so 1955', 'Vista en altura, desde una de las ventanas del "hotelito" m├ís al sureste de la plaza de Arag├│n, de la ajardinada plaza de Para├¡so, y el principio del paseo de Calvo Sotelo. Una unidad de la l├¡nea 11, en direcci├│n al "Parque". El guardia urbano encasetado, pendiente de un improbable desbarajuste automovil├¡stico.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64713800, -0.88567300, '0101000020E61000001B683EE76E57ECBFDAFF006BD5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21792464843.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21792464843.webp', 'https://www.flickr.com/photos/zaragozaantigua/21792464843/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25242, 'Pl. de Para├¡so 1955', 'A├®rea visual (cortes├¡a de la Fuerza A├®rea de los Estados Unidos de Norteam├®rica) del entorno de la plaza de Para├¡so, como nodal enlace al oeste con la plaza de Arag├│n, al norte con el paseo de Marina Moreno, al este con General Mola y paseo de las Damas, al sureste con Calvo Sotelo, y al suoeste con el paseo de Pamplona. En primer plano, el gran complejo jesu├¡tico (Colegio y Residencia Universitaria), a├║n sin la nueva iglesia de quita y pon.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64732300, -0.88583900, '0101000020E6100000DAAED007CB58ECBF6C79E57ADBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22252138561.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22252138561.webp', 'https://www.flickr.com/photos/zaragozaantigua/22252138561/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25243, 'Plaza de Para├¡so 1955', 'Despejada vista en altura, desde el inmediato edificio "El├¡seos", de la plaza, y de un panorama luminoso y provinciano. En primer├¡simo plano, uno de los recientes trolebuses "Pegaso-Escoriaza" de Material M├│vil y Construcciones, realizando el retorno de la l├¡nea "Terminillo". En la rotonda ajardinada, el funcionario municipal de tr├ífico que controla la circulaci├│n sigue al raso. Pronto le pondr├ín una sombrilla, por el sol, y m├ís tarde un p├║lpito. Cosas del progreso. Fuente visual: www.delcampe.net/', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64713800, -0.88567300, '0101000020E61000001B683EE76E57ECBFDAFF006BD5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22576031184.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22576031184.webp', 'https://www.flickr.com/photos/zaragozaantigua/22576031184/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25244, 'Plaza Para├¡so 2012', 'Foto: Jaime Galindo. Vista de la plaza de Basilio Para├¡so durante sus obras de remodelaci├│n en 2012 para prolongar la l├¡nea 1 del tranv├¡a. Fuente: El Peri├│dico de Arag├│n.', 2012, 2012, 2012, 'Siglo XXI', 'CENTRO', 41.64720400, -0.88575200, '0101000020E61000001FBB0B941458ECBF92EBA694D7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25498465982.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25498465982.webp', 'https://www.flickr.com/photos/zaragozaantigua/25498465982/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25245, 'Pl. de Para├¡so 1955', 'Imagen de la plaza de Para├¡so, despejada tras la recolocaci├│n del est├ítico Cesar Augusto en las murallas de piedra de la ciudad. Tras la verde y florida rotonda, la Facultad de Medicina y Ciencias, y un troleb├║s (posiblemente, un Pegaso-Escoriaza) de la l├¡nea del "Terminillo", de regreso de ese destino. A la izquierda, arranque del paseo de Calvo Sotelo. Fuente visual: Garc├¡a Garrabella, en www.todocoleccion.net/', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64720400, -0.88575200, '0101000020E61000001FBB0B941458ECBF92EBA694D7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25669414836.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25669414836.webp', 'https://www.flickr.com/photos/zaragozaantigua/25669414836/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25246, 'Puerta de Santa Engracia 1899', '"Puerta de San Engration. Plaza d''Aragon", Ren├® Ancely, 1899. Tras la puerta de Santa Engracia, de la que destacan las casetas de cobro de consumos, a la izquierda, el nov├¡simo e historicista edificio de la Capitan├¡a General de Arag├│n, y el arranque de los vecinos hotelitos. A la derecha, ingreso a la plaza de Arag├│n, donde todav├¡a estaba presidi├®ndola el bulto redondo de Ram├│n Pignatelli. Hac├¡a tiempo que por aqu├¡ transitaban las unidades del tranv├¡a hacia Torrero.', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.64758900, -0.88581600, '0101000020E6100000CFC0C8CB9A58ECBFEB1F4432E4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27100992000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27100992000.webp', 'https://www.flickr.com/photos/zaragozaantigua/27100992000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25247, 'Puente de Santa Engracia 1899', '"Universit├® Facult├® de m├®decine et des sciences", Ren├® Ancely, 1899. Un veh├¡culo a propulsi├│n de sangre transita tranquilo por el puente de Santa Engracia sobre el cauce al aire del r├¡o Huerva, posiblemente en direcci├│n al paseo de Sagasta. De tel├│n de fondo, el reciente edificio de las Facultades de Medicina y Ciencias. Sobre el terroso firme, el tendido de la tranviaria l├¡nea de Torrero, que desde la plaza de la Constituci├│n llegaba hasta poco antes de la "playa" junto al Canal Imperial. Justo a la izquierda, ya fuera de plano, el Vel├│dromo de los Campos El├¡seos. Fuente visual: www.georgesancely.com/', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.64711600, -0.88576200, '0101000020E61000000344C18C2958ECBFF25B74B2D4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27342974396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27342974396.webp', 'https://www.flickr.com/photos/zaragozaantigua/27342974396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25248, 'Facultad de Medicina 1893', 'Imagen desde cierta altura (posiblemente, desde el n┬║ 8 de la Glorieta de PIgnatelli) con panorama de la nov├¡sima Facultad de Medicina y Ciencias, a├║n en obras, y un primer plano de la tercera (y ├║ltima) puerta de Santa Engracia como controlado acceso a la referida glorieta y la calle de la Independencia. Por esta puerta ya transitaba el tranv├¡a a sangre hacia la playa de Torrero. A la izquierda, arranque del puente de Santa Engracia sobre el Huerva, y al fondo el cauce al aire de este r├¡o, con alguna de las f├íbricas del Camino de los Cubos. Hacia la derecha, el paseo de la Lealtad. Esta imagen fue publicada en octubre de 1893. Fuente: "El Diario de Zaragoza"', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64758900, -0.88581600, '0101000020E6100000CFC0C8CB9A58ECBFEB1F4432E4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27597312566.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27597312566.webp', 'https://www.flickr.com/photos/zaragozaantigua/27597312566/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25249, 'Plaza Para├¡so 2011', 'Foto: Jos├® Miguel Marco. Vista de la plaza de Basilio Para├¡so el 27 del octubre de 2011 desde el edificio central de Ibercaja, durante las obras de remodelaci├│n con motivo de la prolongaci├│n de la l├¡nea 1 del tranv├¡a. Fuente: Heraldo de Arag├│n.', 2011, 2011, 2011, 'Siglo XXI', 'CENTRO', 41.64718600, -0.88574000, '0101000020E61000000E4A9869FB57ECBFEB36A8FDD6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27861286129.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27861286129.webp', 'https://www.flickr.com/photos/zaragozaantigua/27861286129/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23814, 'El Pilar c.1905', 'Vista del Pilar hacia 1905, cuando la segunda torre estaba a medio hacer. Fuente: www.facebook.com/photo.php?fbid=10204539479060566&set...', 1905, 1905, 1905, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65780800, -0.87773300, '0101000020E6100000C7D633846316ECBF0A86730D33D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15739621358.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15739621358.webp', 'https://www.flickr.com/photos/zaragozaantigua/15739621358/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25250, 'R├¡o Huerva 1861', 'Aspecto del actual paseo de la Constituci├│n, visto desde el puente de Santa Engracia sobre el r├¡o Huerva. Al fondo a la derecha, iglesia de San Miguel. Fuente: Mariano J├║dez y Ortiz. ├ülbum de Andr├®s Mart├¡n e Ip├ís. Colecci├│n Mariano Mart├¡n Casalderrey. Libro Primeros tiempos de la fotograf├¡a en Zaragoza', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.64728400, -0.88522600, '0101000020E61000006534F279C553ECBFAE9CBD33DAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27967123764.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27967123764.webp', 'https://www.flickr.com/photos/zaragozaantigua/27967123764/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25252, 'Plaza de Para├¡so 1955', 'Vista en altura capturada desde el edificio El├¡seos" de la inmediata plaza de Para├¡so, la plaza de Arag├│n y el antiguo paseo de la Independencia, y el arranque a la derecha de la avenida de Marina Moreno. Transitan trolebuses de la l├¡nea "Terminillo", y tranv├¡a de la l├¡nea de Venecia-Delicias. Fuente visual: www.delcampe.net/', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64713000, -0.88578500, '0101000020E61000000E32C9C85958ECBF5721E527D5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31291812343.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31291812343.webp', 'https://www.flickr.com/photos/zaragozaantigua/31291812343/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25253, 'Vista a├®rea plaza Para├¡so 1957', 'Vista a├®rea de la plaza de Basilio Para├¡so y su entorno. Junto a ├®sta, arriba, el colegio del Salvador; y abajo, la Facultad de Medicina y Ciencias. Fuente: TAF Helic├▓pters. Arxiu Nacional de Catalunya.', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.64731900, -0.88586200, '0101000020E6100000E59CD843FB58ECBF2B8A5759DBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31321374556.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31321374556.webp', 'https://www.flickr.com/photos/zaragozaantigua/31321374556/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25254, 'Patio de la Infanta 2007', 'Foto: Juan Carlos Arcos. Presentaci├│n del libro "Conversaciones con Jos├® Joaqu├¡n Sancho Dronda" en el Patio de la Infanta, inserto en el edificio central de Ibercaja. En primer plano, Manuel Pizarro, presidente de la Bolsa de Madrid en 1991, presidente de Ibercaja entre 1995 y 2004, presidente de Endesa entre 2002 y 2007, diputado en el Congreso por el Partido Popular entre 2008 y 2010 y adjunto a la presidencia de El Corte Ingl├®s en 2014. Le sigue Jos├® Joaqu├¡n Sancho Dronda, secretario general del Banco de Arag├│n de 1953 a 1965, director general de la Caja de Ahorros de Zaragoza entre 1965 y 1987, presidente de El├®ctricas Reunidas de Zaragoza, presidente de CASER, presidente de los patronatos del Colegio Mayor Miraflores de Zaragoza y del santuario de Torreciudad, ambos pertenecientes al Opus Dei, impulsor de Formigal y de la instalaci├│n de General Motors en Figueruelas. Tras ├®l, Amado Franco, presidente de El├®ctricas Reunidas de Zaragoza en 1997 y presidente de Ibercaja desde 2004. M├ís all├í, Javier Andreu, el autor del libro y profesor de Historia Antigua en la Universidad de Navarra, perteneciente al Opus Dei. Fuente visual: Heraldo de Arag├│n.', 2007, 2007, 2007, 'Siglo XXI', 'CENTRO', 41.64660900, -0.88474400, '0101000020E610000094A12AA6D24FECBF4E266E15C4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32213138652.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32213138652.webp', 'https://www.flickr.com/photos/zaragozaantigua/32213138652/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25258, 'Pl. de Para├¡so 1954', 'Luminosa imagen capturada desde la altura del chaflanero Edificio El├¡seos con bien despejada vista, en primer t├®rmino, de la plaza de Para├¡so y el arranque del paseo de Pamplona. Hacia el fondo, la plaza de Arag├│n y el paseo de la Independencia densamente arbolados, mientras una unidad tranviaria de la serie 200, posiblemente en servicio en la l├¡nea 11 "Parque", se dirige hacia all├¡. La ovalada isleta central de la plaza de Para├¡so se nos muestra con su austero y enjuto aspecto desde que se le despoj├│ de la imperial estatua de C├®sar Augusto, y hasta que fue remozada para albergar una luminosa y luego problem├ítica fuente. Al fondo, la vieja ciudad con sus jalones principales desde la torre de San Pablo, la c├║pula de Santiago y el Front├│n Aragon├®s, a la izquierda, hasta la iglesia de Santa Engracia, a la derecha. Fuente visual: Ediciones Sicilia, en www.delcampe.net', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64717000, -0.88574000, '0101000020E61000000E4A9869FB57ECBFE6797077D6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45448123532.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45448123532.webp', 'https://www.flickr.com/photos/zaragozaantigua/45448123532/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25259, 'Pl. de Basilio Para├¡so 1954', 'Imagen capturada desde la altura del Edificio Eliseos, sobre el inmueble del n┬║ 3 del paseo de Calvo Sotelo, con una interesante vista panor├ímica del entorno de la plaza de Para├¡so, su engarce con la arbolada plaza de Arag├│n y el paseo de la Independencia, y con el original y reciente tramo inicial del bulevar de la avenida de Marina Moreno, a la derecha extrema. A la izquierda, e inmediata, la Facultad de Medicina y Ciencia de la Universidad. Por la plaza transita una composici├│n tranviaria de la l├¡nea 5 "Venecia-Delicias" en descenso hacia la plaza de Espa├▒a, y una unidad de la l├¡nea 11 "Parque" hacia el parque de Primo de Rivera. Al fondo, variado horizonte del que despuntan algunas torres y c├║pulas de la vieja ciudad, y hasta de las chimeneas de la Azucarera de Arag├│n o del Arrabal, al otro lado del r├¡o Ebro.', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64717000, -0.88574000, '0101000020E61000000E4A9869FB57ECBFE6797077D6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46368626735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46368626735.webp', 'https://www.flickr.com/photos/zaragozaantigua/46368626735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25260, 'Puerta de Santa Engracia c.1895', 'In├®dita imagen capturada desde la altura del esquinero inmueble del n┬║ 8 de la glorieta de Pignatelli, luego plaza de Arag├│n, con una vista parcial de la tercera y ├║ltima versi├│n contempor├ínea de la Puerta de Santa Engracia, casi eclipsada en este caso por el majestuoso fondo edilicio de la nov├¡sima Facultad de Medicina y Ciencias de la Universidad.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64762200, -0.88556800, '0101000020E6100000C74ACCB39256ECBFC6151747E5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48049544058.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48049544058.webp', 'https://www.flickr.com/photos/zaragozaantigua/48049544058/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25261, 'Plaza de Basilio Para├¡so c.1958', 'Imagen capturada posiblemente desde la altura de la fachada principal del colegio del Salvador recayente al paseo del General Mola, con una interesante vista orientada hacia la plaza de Basilio Para├¡so y el paseo de Pamplona. A la izquierda destaca la mole del Edificio El├¡seos, rematado por la luminosa peineta publicitaria corporativa. Tras la Facultad de Medicina y Ciencias y el ingreso a la calle del Doctor Cerrada, el reciente inmueble del n┬║ 1 del paseo de Pamplona. Hacia el fondo, el bulevar de este paseo alcanza hasta la rotonda de la Puerta del Carmen, tras la que se extiende el enorme espacio de la huerta del convento de la Encarnaci├│n y la huerta del Hospital Provincial, la Casa y Noviciado de las Hermanas de la Caridad de Santa Ana, y el Hospicio Provincial. De la plaza del Portillo emerge, a la derecha, la c├║pula que remata la sucursal de la agencia n┬║ 1 de una importante entidad de ahorro local. En primer t├®rmino y encaminada hacia la terminal de la plaza del Emperador Carlos V, una unidad de la serie 200 en servicio en la tranviaria l├¡nea 11. Parque.', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64639900, -0.88540700, '0101000020E61000007AC8940F4155ECBF6495D233BDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49575046281.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49575046281.webp', 'https://www.flickr.com/photos/zaragozaantigua/49575046281/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25345, 'Plaza de Arag├│n 1983', 'Imagen capturada desde cierta altura, con un buen panorama de la plaza de Para├¡so, la de Arag├│n, y el paseo de la Independencia. La estatua de C├®sar Augusto ha sido regresada, aproximadamente, a sus imperiales or├¡genes, ahora en una exuberante rotonda automovil├¡stica. La plaza de Arag├│n progresa adecuadamente en el sobresaliente recrecimiento de sus edificios. Al fondo, la autopista de la Independencia, y la antigua fachada provinciana del Coso a la plaza de Espa├▒a, que todav├¡a permite ver el emergente bloque del principio de la calle Sixto Celorrio, al otro lado del Ebro. Fuente visual: www.ebay.es/', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.64754400, -0.88577600, '0101000020E6100000419DF2E84658ECBF4B5CC7B8E2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31278229801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31278229801.webp', 'https://www.flickr.com/photos/zaragozaantigua/31278229801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
